 1	import React, { FC } from 'react';
 2	
 3	import { modelToGroupVersionKind, NodeModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import VirtualMachineModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineModel';
 5	import { IoK8sApiCoreV1Node } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 6	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 7	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import { asAccessReview } from '@kubevirt-utils/resources/shared';
10	import {
11	  K8sVerb,
12	  useAccessReview,
13	  useK8sWatchResource,
14	} from '@openshift-console/dynamic-plugin-sdk';
15	import { Grid, GridItem, Title } from '@patternfly/react-core';
16	
17	import SchedulingSectionLeftGrid from './SchedulingSectionLeftGrid';
18	import SchedulingSectionRightGrid from './SchedulingSectionRightGrid';
19	
20	type SchedulingSectionProps = {
21	  instanceTypeVM?: V1VirtualMachine;
22	  onSubmit?: (updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine>;
23	  vm: V1VirtualMachine;
24	  vmi?: V1VirtualMachineInstance;
25	};
26	
27	const SchedulingSection: FC<SchedulingSectionProps> = ({ instanceTypeVM, onSubmit, vm, vmi }) => {
28	  const { t } = useKubevirtTranslation();
29	  const [nodes, nodesLoaded] = useK8sWatchResource<IoK8sApiCoreV1Node[]>({
30	    groupVersionKind: modelToGroupVersionKind(NodeModel),
31	    isList: true,
32	  });
33	  const accessReview = asAccessReview(VirtualMachineModel, vm, 'update' as K8sVerb);
34	  const [canUpdateVM] = useAccessReview(accessReview || {});
35	
36	  return (
37	    <>
38	      <Title headingLevel="h2">
39	        <SearchItem id="scheduling">{t('Scheduling and resource requirements')}</SearchItem>
40	      </Title>
41	      <Grid hasGutter>
42	        <SchedulingSectionLeftGrid
43	          canUpdateVM={canUpdateVM}
44	          nodes={nodes}
45	          nodesLoaded={nodesLoaded}
46	          onUpdateVM={onSubmit}
47	          vm={vm}
48	          vmi={vmi}
49	        />
50	        <GridItem span={1}>{/* Spacer */}</GridItem>
51	        <SchedulingSectionRightGrid
52	          canUpdateVM={canUpdateVM}
53	          instanceTypeVM={instanceTypeVM}
54	          onUpdateVM={onSubmit}
55	          vm={vm}
56	          vmi={vmi}
57	        />
58	      </Grid>
59	    </>
60	  );
61	};
62	
63	export default SchedulingSection;

